  "Reputation enrichment unavailable right now—your baseline scan findings still apply.": { nl: "Reputatieverrijking nu niet beschikbaar—uw basisscanresultaten blijven gelden.", de: "Reputationsanreicherung derzeit nicht verfügbar—Ihre Basis-Scan-Ergebnisse gelten weiter.", fr: "Enrichissement de réputation indisponible pour l’instant—les résultats de base s’appliquent toujours.", es: "Enriquecimiento de reputación no disponible ahora—siguen aplicando los hallazgos del análisis base.", pt: "Enriquecimento de reputação indisponível agora—os resultados da verificação base continuam a aplicar-se." },
  "Review collector notes (neutral)": { nl: "Notities reviewverzamelaar (neutraal)", de: "Hinweise Review-Sammler (neutral)", fr: "Notes collecteur d’avis (neutre)", es: "Notas del recolector de reseñas (neutral)", pt: "Notas do recolhedor de avaliações (neutro)" },
