  "Trust score withheld — this hostname is not treated as an active website.": { nl: "Vertrouwensscore verborgen — deze hostnaam wordt niet als actieve website behandeld.", de: "Vertrauenswert ausgeblendet — dieser Hostname gilt nicht als aktive Website.", fr: "Score masqué — ce nom d’hôte n’est pas traité comme site actif.", es: "Puntuación oculta — este host no se trata como sitio activo.", pt: "Pontuação oculta — este hostname não é tratado como site ativo." },
  "Trust-positive signals": { nl: "Vertrouwen-positieve signalen", de: "Vertrauenspositive Signale", fr: "Signaux positifs pour la confiance", es: "Señales positivas de confianza", pt: "Sinais positivos de confiança" },
